import{c as a,Q as s,j as t,m as o}from"./chunks/framework.CTNaDwNv.js";const u=JSON.parse('{"title":"Install on a server","description":"","frontmatter":{},"headers":[],"relativePath":"guide/install.md","filePath":"guide/install.md","lastUpdated":1779853631000}'),n={name:"guide/install.md"};function i(d,e,r,c,l,p){return s(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="install-on-a-server" tabindex="-1">Install on a server <a class="header-anchor" href="#install-on-a-server" aria-label="Permalink to &quot;Install on a server&quot;">â€‹</a></h1><h2 id="distribution-paths" tabindex="-1">Distribution paths <a class="header-anchor" href="#distribution-paths" aria-label="Permalink to &quot;Distribution paths&quot;">â€‹</a></h2><p>There are three ways to install <code>agent_api</code> on a FiveM server.</p><h3 id="a-drop-in-folder-recommended-for-production" tabindex="-1">A. Drop-in folder (recommended for production) <a class="header-anchor" href="#a-drop-in-folder-recommended-for-production" aria-label="Permalink to &quot;A. Drop-in folder (recommended for production)&quot;">â€‹</a></h3><p>Build a clean folder once, copy it anywhere.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/mysbryce/5m-mcp.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 5m-mcp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> generate:resource</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># â†’ out/agent_api/   (no node_modules, no src/, no dev cruft)</span></span></code></pre></div><p>Then copy <code>out/agent_api/</code> into your FiveM server&#39;s <code>resources/[agent]/agent_api/</code>.</p><p>The drop-in folder contains:</p><ul><li><code>fxmanifest.lua</code></li><li><code>dist/server.js</code>, <code>dist/client.js</code>, <code>dist/mcp-stdio.js</code>, <code>dist/screenshot-nui.js</code></li><li><code>README.md</code></li></ul><p>Total size: ~400 KB.</p><h3 id="b-symlink-dev-loop" tabindex="-1">B. Symlink (dev loop) <a class="header-anchor" href="#b-symlink-dev-loop" aria-label="Permalink to &quot;B. Symlink (dev loop)&quot;">â€‹</a></h3><p>If you&#39;re hacking on <code>agent_api</code> itself, junction the repo into the server so <code>restart agent_api</code> always picks up the latest <code>dist/*.js</code>.</p><div class="language-pwsh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">pwsh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pwsh -File scripts/dev-link.ps1 -ServerRoot &lt;txData base&gt;</span></span></code></pre></div><p>The script needs no admin rights â€” it uses NTFS junctions, not symlinks. After running, <code>npm run watch</code> in the repo rebuilds <code>dist/</code> on save; <code>restart agent_api</code> in FiveM picks up the change.</p><h3 id="c-git-clone-inside-the-resources-folder" tabindex="-1">C. Git clone inside the resources folder <a class="header-anchor" href="#c-git-clone-inside-the-resources-folder" aria-label="Permalink to &quot;C. Git clone inside the resources folder&quot;">â€‹</a></h3><p>Functionally the same as B but without the junction layer. Make sure <code>node_modules</code> and <code>dist/</code> exist (<code>npm install &amp;&amp; npm run build</code>).</p><h2 id="first-start" tabindex="-1">First start <a class="header-anchor" href="#first-start" aria-label="Permalink to &quot;First start&quot;">â€‹</a></h2><p>In the FiveM server console:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>refresh</span></span>
<span class="line"><span>ensure agent_api</span></span></code></pre></div><p>The resource auto-generates a token on first start. Look for the banner:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[agent_api] No token configured. Generated new token.</span></span>
<span class="line"><span>[agent_api] Saved to: dist/.agent_token</span></span></code></pre></div><p>The token is persisted to <code>dist/.agent_token</code> (mode 0600 on POSIX). On subsequent starts it&#39;s loaded silently.</p><p>If you&#39;d rather pin the token, set the convar before first start:</p><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set agent_api_token &quot;your-pre-shared-token&quot;</span></span></code></pre></div><h2 id="ace-permissions" tabindex="-1">ACE permissions <a class="header-anchor" href="#ace-permissions" aria-label="Permalink to &quot;ACE permissions&quot;">â€‹</a></h2><p>Lifecycle commands (<code>ensure/start/stop/restart/refresh/say</code>) need ACE rights for the resource:</p><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>add_ace resource.agent_api command.ensure  allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.start   allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.stop    allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.restart allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.refresh allow</span></span>
<span class="line"><span>add_ace resource.agent_api command.say     allow</span></span></code></pre></div><p>To open every command (looser, simpler):</p><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>add_ace resource.agent_api command allow</span></span></code></pre></div><h2 id="optional-nui-screenshots" tabindex="-1">Optional: NUI screenshots <a class="header-anchor" href="#optional-nui-screenshots" aria-label="Permalink to &quot;Optional: NUI screenshots&quot;">â€‹</a></h2><p><code>screenshot_nui</code> connects to FiveM&#39;s CEF DevTools (port 13172) over WebSocket. <strong>No separate browser install required</strong> â€” we attach to the running CEF, no headless Chrome involved.</p><p>The port is opened by default. If you&#39;ve changed it, pass <code>cdpUrl</code> to the tool call.</p><h2 id="optional-shell-commands" tabindex="-1">Optional: shell commands <a class="header-anchor" href="#optional-shell-commands" aria-label="Permalink to &quot;Optional: shell commands&quot;">â€‹</a></h2><p><code>run_shell</code> lets the agent execute <code>npm</code>, <code>npx</code>, <code>pnpm</code>, <code>yarn</code>, <code>bun</code>, <code>vite</code>, <code>git</code>, or <code>node</code> inside a resource folder. The binaries must be on the server host&#39;s PATH.</p><p>For <code>npm create vite</code> in particular, ensure your Node install includes <code>npx</code> (it does by default).</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">â€‹</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Cause</th><th>Fix</th></tr></thead><tbody><tr><td><code>[cmd] Access denied for command ensure</code></td><td>ACE not granted</td><td>add the <code>add_ace</code> lines above to <code>server.cfg</code>, restart</td></tr><tr><td><code>screenshot_nui</code> returns <code>cannot reach CDP at http://localhost:13172</code></td><td>no FiveM client connected; FXServer instance has no CEF</td><td>start the FiveM client and connect</td></tr><tr><td><code>RESOURCE_NOT_FOUND</code> after <code>create_resource</code></td><td>folder created but FiveM hasn&#39;t re-scanned</td><td>call <code>refresh_resources</code> between <code>create_resource</code> and <code>write_file</code></td></tr><tr><td><code>PATH_OUTSIDE_SANDBOX</code> on a fresh write</td><td>write root convar doesn&#39;t match the target resource&#39;s path</td><td>set <code>agent_api_allow_write_paths</code> to a CSV including the parent folder, or move the resource under <code>resources/[agent]/</code></td></tr><tr><td>Server SIGSEGV after <code>ensure_resource agent_api</code></td><td>hit a known FiveM Mono race</td><td>the self-target guard now refuses this â€” update to the latest build</td></tr></tbody></table>`,37)])])}const g=a(n,[["render",i]]);export{u as __pageData,g as default};
